function initBurger() {
    function bodyLock() {
        body.classList.add('_lock');
        lenis.destroy();

    }

    function bodyUnLock() {
        body.classList.remove('_lock');

        lenis = new Lenis()

        function raf(time) {
            lenis.raf(time)
            requestAnimationFrame(raf)
        }

        requestAnimationFrame(raf)
    }

    // Lenis Scroll
    let lenis = new Lenis()

    function raf(time) {
        lenis.raf(time)
        requestAnimationFrame(raf)
    }

    requestAnimationFrame(raf)

    // Burger
    let body = document.querySelector('body');
    let burger = document.querySelector('.header__burger');
    let burger_close = document.querySelector('.mobile-header__close');
    let mobile_header = document.querySelector('.mobile-header');

    if (burger) {
        burger.addEventListener('click', function (event) {
            event.preventDefault();

            bodyLock();

            if (mobile_header) {
                mobile_header.classList.add('active');
            }
        })
    }

    if (burger_close) {
        burger_close.addEventListener('click', function (event) {
            event.preventDefault();

            bodyUnLock();

            if (mobile_header) {
                mobile_header.classList.remove('active');
            }
        })
    }
}

