let all_items_hover = document.querySelectorAll('.items-hover');

if(all_items_hover.length){
    all_items_hover.forEach(function(items_hover){
        let all_item_hover = items_hover.querySelectorAll('.items-hover__item');

        if(all_item_hover.length){
            all_item_hover.forEach(function(item_hover){
                item_hover.addEventListener('mouseover', function(){
                    itemHover(all_item_hover, item_hover);
                });

                item_hover.addEventListener('click', function(){
                    itemHover(all_item_hover, item_hover);
                });
            })
        }
    })
}

function itemHover(items, item){
    items.forEach(function(element){
        element.classList.remove('hover');
    });

    item.classList.add('hover');
}

